// ── Confetti ──────────────────────────────────────────────────────────────────
function Confetti({ active }) {
  const [particles, setParticles] = useState([]);
  useEffect(() => {
    if (!active) return;
    const colors = ["#e8001a","#ff6b00","#fff","#25d366","#a855f7"];
    const ps = Array.from({ length: 60 }, (_, i) => ({
      id: i,
      x: 30 + Math.random() * 40,
      y: 40 + Math.random() * 20,
      color: colors[Math.floor(Math.random() * colors.length)],
      size: 4 + Math.random() * 6,
      rot: Math.random() * 360,
    }));
    setParticles(ps);
    const t = setTimeout(() => setParticles([]), 2800);
    return () => clearTimeout(t);
  }, [active]);
  if (!particles.length) return null;
  return (
    <div style={{ position:"fixed", inset:0, pointerEvents:"none", zIndex:9999, overflow:"hidden" }}>
      {particles.map(p => (
        <div key={p.id} style={{
          position:"absolute", left: p.x+"%", top: p.y+"%",
          width: p.size, height: p.size, background: p.color,
          borderRadius: Math.random()>0.5?"50%":"2px",
          animation: "cfall "+p.id%5*0.3+2+"s ease-in forwards",
          transform: "rotate("+p.rot+"deg)",
        }} />
      ))}
      <style>{`
        @keyframes cfall { to { transform: translate(0,600px) rotate(720deg); opacity:0; } }
      `}</style>
    </div>
  );
}

// ── Magnetic button hook ──────────────────────────────────────────────────────
function useMagnetic() {
  const ref = useRef(null);
  const onMouseMove = useCallback(e => {
    const el = ref.current; if (!el) return;
    const r = el.getBoundingClientRect();
    const dx = (e.clientX - r.left - r.width/2)  * 0.32;
    const dy = (e.clientY - r.top  - r.height/2) * 0.32;
    el.style.transform = "translate("+dx+"px,"+dy+"px) scale(1.06)";
  }, []);
  const onMouseLeave = useCallback(() => {
    if (ref.current) ref.current.style.transform = "translate(0,0) scale(1)";
  }, []);
  return { ref, onMouseMove, onMouseLeave };
}

// ── Scroll reveal hook ────────────────────────────────────────────────────────
function useReveal(threshold) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setVisible(true); obs.disconnect(); } }, { threshold: threshold || 0.15 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return { ref, visible };
}

// ── Typing effect ─────────────────────────────────────────────────────────────
function useTyping(words, speed, pause) {
  const [display, setDisplay] = useState("");
  const [wi, setWi]       = useState(0);
  const [ci, setCi]       = useState(0);
  const [del, setDel]     = useState(false);
  useEffect(() => {
    const word = words[wi];
    const t = setTimeout(() => {
      if (!del) {
        setDisplay(word.slice(0, ci+1));
        if (ci+1 === word.length) setTimeout(() => setDel(true), pause||1800);
        else setCi(ci+1);
      } else {
        setDisplay(word.slice(0, ci-1));
        if (ci-1 === 0) { setDel(false); setWi((wi+1)%words.length); setCi(0); }
        else setCi(ci-1);
      }
    }, del ? (speed||80)/2 : (speed||80));
    return () => clearTimeout(t);
  }, [display, wi, ci, del, words, speed, pause]);
  return display;
}

// ── Motive card ───────────────────────────────────────────────────────────────
function MotiveCard({ icon, titulo, corpo, delay }) {
  const { ref, visible } = useReveal(0.1);
  const [hovered, setHovered] = useState(false);
  return (
    <div ref={ref}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: hovered ? "rgba(232,0,26,0.08)" : "rgba(255,255,255,0.03)",
        border: "1px solid "+(hovered ? "rgba(232,0,26,0.35)" : "rgba(255,255,255,0.07)"),
        borderRadius: "6px", padding: "36px 30px", cursor: "default",
        position: "relative", overflow: "hidden",
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(32px)",
        transition: "opacity 0.7s ease "+delay+"ms, transform 0.7s ease "+delay+"ms, background 0.3s, border-color 0.3s",
      }}>
      <div style={{ position:"absolute", width:"120px", height:"120px",
        background:"radial-gradient(circle, rgba(232,0,26,0.2), transparent 70%)",
        top:"-40px", right:"-40px", borderRadius:"50%",
        opacity: hovered?1:0, transition:"opacity 0.4s", pointerEvents:"none" }} />
      <div style={{ fontSize:"34px", marginBottom:"14px" }}>{icon}</div>
      <h3 style={{ margin:"0 0 10px", fontSize:"18px", fontWeight:"700",
        color: hovered?"#fff":"#e0e0e0", transition:"color 0.3s",
        fontFamily:"Georgia,serif" }}>{titulo}</h3>
      <p style={{ margin:0, fontSize:"15px", color:"#888", lineHeight:1.7 }}>{corpo}</p>
    </div>
  );
}


// ── Cursor glow effect ────────────────────────────────────────────────────────
function CursorGlow() {
  const dotRef   = useRef(null);
  const glowRef  = useRef(null);

  useEffect(() => {
    const onMove = e => {
      const x = e.clientX;
      const y = e.clientY;
      if (dotRef.current) {
        dotRef.current.style.left = x + "px";
        dotRef.current.style.top  = y + "px";
      }
      if (glowRef.current) {
        glowRef.current.style.left = x + "px";
        glowRef.current.style.top  = y + "px";
      }
    };
    window.addEventListener("mousemove", onMove);
    return () => window.removeEventListener("mousemove", onMove);
  }, []);

  return (
    <div style={{ position:"fixed", inset:0, zIndex:5, pointerEvents:"none" }}>
      {/* Outer soft glow */}
      <div ref={glowRef} style={{
        position:"absolute", left:"-999px", top:"-999px",
        width:"320px", height:"320px", borderRadius:"50%",
        background:"radial-gradient(circle, rgba(120,60,220,0.10) 0%, rgba(0,180,130,0.05) 45%, transparent 70%)",
        transform:"translate(-50%,-50%)",
        willChange:"left,top",
      }} />
      {/* Shadow */}
      <div ref={dotRef} style={{
        position:"absolute", left:"-999px", top:"-999px",
        width:"140px", height:"140px", borderRadius:"50%",
        background:"radial-gradient(circle, rgba(140,70,255,0.45) 0%, rgba(80,200,160,0.18) 45%, transparent 72%)",
        filter:"blur(12px)",
        transform:"translate(-50%,-50%)",
        willChange:"left,top",
      }} />
    </div>
  );
}

